class IslandInfo:
    def __init__(self, faces, index):
        self.faces = faces
        self.index = index
        self.avg_normal = Vector((0, 0, 1))
        self.type = PatchType.WALL.value
        self.area = 0.0
        self.perimeter = 0.0

