    num = 0.0
    den = 0.0
    for i in range(n):
        s = target_uvs_list[i] - target_centroid
        t = anchor_uvs_list[i] - anchor_centroid
        num += s.x * t.y - s.y * t.x
        den += s.x * t.x + s.y * t.y
    
    angle = math.atan2(num, den) if abs(num) > 1e-10 or abs(den) > 1e-10 else 0.0
    return angle, anchor_centroid, target_centroid

